#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int *left = (int*)calloc(N + 1, sizeof(int));
        int *right = (int*)calloc(N + 1, sizeof(int));
        int *isChild = (int*)calloc(N + 1, sizeof(int));
        for (int i = 0; i < N - 1; ++i) {
            int p, c; char dir;
            scanf("%d %d %c", &p, &c, &dir);
            if (dir == 'L') left[p] = c; else right[p] = c;
            isChild[c] = 1;
        }
        int root = 1;
        for (int i = 1; i <= N; ++i) if (!isChild[i]) { root = i; break; }
        int *stack = (int*)malloc((N + 5) * sizeof(int));
        int top = -1;
        int cur = root;
        int first = 1;
        while (cur || top != -1) {
            while (cur) {
                stack[++top] = cur;
                cur = left[cur];
            }
            cur = stack[top--];
            if (!first) printf(" ");
            printf("%d", cur);
            first = 0;
            cur = right[cur];
        }
        printf("\n");
        free(left); free(right); free(isChild); free(stack);
    }
    return 0;
}

