const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
function inorderIter(root, left, right) {
    const stack = [];
    let cur = root;
    const res = [];
    while (cur !== 0 || stack.length) {
        while (cur !== 0) {
            stack.push(cur);
            cur = left[cur];
        }
        cur = stack.pop();
        res.push(String(cur));
        cur = right[cur];
    }
    return res.join(' ');
}
for (let t = 0; t < T; ++t) {
    const N = Number(input[idx++]);
    const left = new Array(N + 1).fill(0);
    const right = new Array(N + 1).fill(0);
    const isChild = new Array(N + 1).fill(false);
    for (let i = 0; i < N - 1; ++i) {
        const p = Number(input[idx++]);
        const c = Number(input[idx++]);
        const dir = input[idx++];
        if (dir === 'L') left[p] = c; else right[p] = c;
        isChild[c] = true;
    }
    let root = 1;
    for (let i = 1; i <= N; ++i) if (!isChild[i]) { root = i; break; }
    outputs.push(inorderIter(root, left, right));
}
